semantic_equivalence_artifact.original_latex_theorem:
\label{l:saturation of increasing points} Let $\Gamma$ be a semibranch, $a,b\in\Gamma^\circ$ and $\bar{c}=(c_i)_{i<n}, \bar{d}=(d_i)_{i<n}$ finite tuples with $\bar{c}\equiv^{\Rr\Gamma}\bar{d}$. Let $C_0\coloneqq\{c_i\tq \pi_\Gamma(c_i)\in\Gamma^\circ\}$ and $\alpha$ an automorphism of $\Tt^M$ fixing $\Gamma$ setwise. 
\begin{enumerate}[label={\rm{(\arabic*)}}, ref={\rm{\arabic*}}, wide]
\item \label{itm:saturation of increasing points 1} Assume that $\alpha$ is upwards unboundedly increasing in $\Gamma$ and $a>\pi_{\Gamma}(c)$ for all $c\in C_0$. Then, there is $a'>b$ with $a'\bar{d}\equiv^{\Rr\Gamma}a\bar{c}$ and $\alpha(a')>a'$.
\item \label{itm:saturation of increasing points 2} Assume that $\alpha$ is downwards unboundedly increasing in $\Gamma$ and $a<\pi_\Gamma(c)$ for all $c\in C_0$. Then, there is $a'<b$ with $a'\bar{d}\equiv^{\Rr\Gamma}a\bar{c}$ and $\alpha(a')>a'$.
\end{enumerate}
\begin{proof} \begin{enumerate}[label={\rm{(\arabic*)}}, wide]
\item[\hspace{-1.4em}\setcounter{enumi}{1}\theenumi] Write $D_0\coloneqq\{d_i\tq \pi_{\Gamma}(d_i)\in\Gamma^{\circ}\}$. Pick $e\in\Gamma^\circ$ with $e>b$ and $e>\pi_\Gamma(d)$ for each $d\in D_0$ such that $\alpha(e)>e$. Then, by \cref{l:saturation of branch intervals}, there is $a'\bar{d}\equiv^{\Rr\Gamma}a\bar{c}$ with $e<a'<\alpha(e)$. Hence, $a'>b$ and $\alpha(a')>\alpha(e)>a'$.
\item Write $D_0\coloneqq\{d_i\tq \pi_{\Gamma}(d_i)\in\Gamma^{\circ}\}$. Pick $e\in\Gamma^\circ$ with $e<\alpha^{-1}(b)$ and $e<\alpha^{-1}(\pi_\Gamma(d))$ and $e<\pi_\Gamma(d)$ for each $d\in D_0$ such that $\alpha(e)>e$. Then, by \cref{l:saturation of branch intervals}, there is $a'\bar{d}\equiv^{\Rr\Gamma}a\bar{c}$ with $e<a'<\alpha(e)$. Hence, $a'<b$ and $\alpha(a')>\alpha(e)>a'$. \qedhere
\end{enumerate}
\end{proof}

