semantic_equivalence_artifact.original_latex_theorem:
\label{l:construction 1} Let $\Gamma$ be a semibranch and $\alpha$ an automorphism of $\Tt^M$ setwise fixing $\Gamma$. Suppose that $\alpha$ is unboundedly increasing in $\Gamma^{\circ}$ (see \cref{d:unbounded}). Then, there is an automorphism $\beta$ of $\Tt^M$ setwise fixing $\Gamma$ such that:
\begin{enumerate}[label={\rm{(\alph*)}}, wide]
\item $\alpha\beta^{-1}\alpha\beta$ is strictly increasing in $\Gamma^{\circ}$. 
\item If $\Gamma$ is not a branch, $\beta$ setwise fixes every cone above $\max\Gamma$. 
\end{enumerate}
\begin{proof} Let $W\coloneqq\{w \tq \pi_\Gamma(w)\in \Gamma^{\circ}\}$ and $V\coloneqq\{v\tq \pi_\Gamma(v)\notin \Gamma^{\circ}\}$. Let $(w_n)_{n\in\N}$ be an enumeration of $W$ and $(v_n)_{n\in\N}$ an enumeration of $V$.

By back{\hyp}and{\hyp}forth, we recursively construct a chain of partial finite isomorphisms $(\beta_n)_{n\in\N}$ of $\Tt^M$ setwise fixing $\Gamma$ and an increasing sequence $(a_n)_{n\in\Z}$ of elements in $\Gamma^\circ$ with the following properties:
\begin{enumerate}[label={(\roman*)}, wide]
\item $\beta_n:\ X_n\rightarrow Y_n$ with $X_n=\langle X_n\rangle_{\Gamma}$ and $Y_n=\langle Y_n\rangle_{\Gamma}$, and $w_k,v_k\in X_n$ and $w_k,v_k\in Y_n$ for $k<n$.
\item For each $-n<k<n$, we have $\alpha\beta_n(a_{k-1})=\beta_n\alpha^{-1}(a_k)$. In particular, $a_k\in X_n$ for $-n-1<k<n-1$, and $\alpha^{-1}(a_k)\in X_n$ for $-n<k<n$.
\item We have $\alpha(a_{k})>a_{k}$ for $-n-1<k<n$, and $\alpha(c_n)>c_n$ where $c_n\coloneqq\beta_n^{-1}\alpha\beta_n(a_{n-1})$. In particular, $a_{n-1}\in X_n$ and $\alpha\beta_n(a_{n-1})\in Y_n$.
\item For $n\geq 1$, $a_{-n}=\min X_n\cap \Gamma^{\circ}$ and $c_n=\max X_n\cap \Gamma^\circ$.
\item (In case $\Gamma\neq \Gamma^{\circ}$) $\beta_n(v)$ and $v$ are in the same cone above $\gamma\coloneqq \max\Gamma$ for any $v\in X_n$ with $v>\gamma$. Also, $\gamma\in X_n$, $\gamma\in Y_n$ and $\beta_n(\gamma)=\gamma$.
\end{enumerate}

In stage $n$ we construct $\beta_n$ and $(a_k)_{-n\leq k<n}$. 
\begin{enumerate}[wide]
\item[Case $n=0$:] If $\Gamma$ is not a branch, we take $\beta_{0}:\ \gamma\mapsto \gamma$, with $X_{0}=Y_{0}=\{\gamma\}$, where $\gamma\coloneqq\max\Gamma$. If $\Gamma$ is a branch, we take $\beta_0=\emptyset$.
\item[Case $n=1$:] Take any $a_0\in\Gamma^{\circ}$ with $\alpha(a_0)>a_0$. Applying sequentially \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 1}) twice and then \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 2}) twice, we find $b,c_1,b',a_{-1}\in\Gamma^{\circ}$ with $b'<\pi_\Gamma(w_0)<b$ and $a_{-1}<\pi_\Gamma(w_0)<c_1$ such that $\alpha(b)>b$, $\alpha(c_1)>c_1$, $\alpha(b')>b'$, $\alpha(a_{-1})>a_{-1}$ and $a_0c_1\alpha^{-1}(a_0)a_{-1}\equiv^{\Rr\Gamma}b\alpha(b)b'\alpha^{-1}(b')$. By homogeneity, we extend $\beta_0$ to $\beta'_1:\ X'_1\rightarrow Y'_1$ with $\beta'_1:\ a_0c_1\alpha^{-1}(a_0)a_{-1}\mapsto b\alpha(b)b'\alpha^{-1}(b')$ and $w_0\in X'_1\cap Y'_1$.  Further, we restrict $\beta'_1$ so that $X'_1=\langle X_0\, a_0c_1\alpha^{-1}(a_0)a_{-1}w_0{\beta'}^{-1}_1(w_0)\rangle_\Gamma$. If $\Gamma=\Gamma^{\circ}$, we set $\beta_1=\beta_1'$. If $\Gamma\neq\Gamma^\circ$, let $\bar{x}'$ enumerate $X'_1$ and $\bar{y}'$ be the enumeration of $Y'_1$ given by $\beta_1':\ \bar{x}'\mapsto \bar{y}'$. By \cref{l:saturation of cones} and homogeneity, find $u,u'\in \cone_\gamma(v_0)$ such that $v_0u'\bar{x}'\equiv^{\Rr\Gamma}uv_0\bar{y}'$. By homogeneity, we extend $\beta'_1$ to $\beta_1:\ X_1\rightarrow Y_1$ where $X_1=\langle X'_1\, v_0 u'\rangle_\Gamma$ and $v_0u'\mapsto uv_0$. 

Obviously, $\beta_1$ satisfies {\rm{(i)}}. For $-1<k<1$, we have $k=0$, and $\beta_1\alpha^{-1}(a_0)=b'=\alpha\beta_1(a_{-1})$, so {\rm{(ii)}} holds. By construction, $c_1=\beta_1^{-1}\alpha\beta_1(a_0)$ and we have $\alpha(a_k)>a_k$ for $-2<k<1$ and $\alpha(c_1)>c_1$, so we get {\rm{(iii)}}. By construction, $\alpha^{-1}(b')<b'<\pi_\Gamma(w_0)<b<\alpha(b)$, so applying $\beta_1^{-1}$ we get $a_{-1}<\alpha^{-1}(a_0)<\pi_\Gamma(\beta_1^{-1}(w_0))<a_0<c_1$. On the other hand, $a_{-1}<\pi_\Gamma(w_0)<c_1$ too. Hence, by \cref{l:generated}(\ref{itm:generated 6}), we get that $c_1=\max X_1\cap \Gamma^{\circ}$ and $a_{-1}=\min X_1\cap \Gamma^{\circ}$, i.e. {\rm{(iv)}} holds. Finally, in case $\Gamma\neq \Gamma^{\circ}$, by \cref{l:generated}(\ref{itm:generated 8}), we have $\cone(X_1)=\cone_\gamma(v_0\, u')$ and $\cone_\gamma(v_0)=\cone_\gamma(u)=\cone_\gamma(u')$, so {\rm{(v)}} holds.    
\item[Recursion case (case $n+1$):] Suppose $\beta_n:\ X_n\rightarrow Y_n$ and $(a_k)_{-n\leq k<n}$ are already given for $n\geq 1$. Let $\bar{x}$ enumerate $X_n$ and $\bar{y}$ be the enumeration of $Y_n$ given by $\beta_n:\ \bar{x}\mapsto \bar{y}$ .
\begin{enumerate}[label={\rm{Step {\arabic*}:}}, wide]
\item By recursion hypothesis {\rm{(iv)}}, we know that $c_n=\max X_n\cap \Gamma^\circ$ where $c_n\coloneqq\beta_n^{-1}\alpha\beta_n(a_{n-1})$. Set $a_n\coloneqq\alpha(c_n)$. By recursion hypothesis {\rm{(iii)}}, $a_n=\alpha(c_n)>c_n$. Hence, by \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 1}), we can find $b\in\Gamma^\circ$ with $\alpha(b)>b$ and $b>\pi_{\Gamma}(w_n)$ such that $a_n\bar{x}\equiv^{\Rr\Gamma} b\bar{y}$. 
\item Applying \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 1}) again, we can find $c_{n+1}\in\Gamma^{\circ}$ with $\alpha(c_{n+1})>c_{n+1}$ and $c_{n+1}>\pi_{\Gamma}(w_{n})$ such that $c_{n+1}a_n\bar{x}\equiv^{\Rr\Gamma}\alpha(b)b\bar{y}$. 
