\item By homogeneity, we extend $\beta_n$ to a partial isomorphism $\beta'_{n+1}:\ X'_{n+1}\rightarrow Y'_{n+1}$ with $\beta'_{n+1}:\ a_{-n-1}\alpha^{-1}(a_{-n})c_{n+1}a_n\mapsto \alpha^{-1}(b')b'\alpha(b)b$ and $w_n\in X'_{n+1}\cap Y'_{n+1}$. Further, we restrict $\beta'_{n+1}$ so that $X'_{n+1}=\langle X_n\, a_{-n-1}\alpha^{-1}(a_{-n})$ $c_{n+1}a_nw_n{\beta'}^{-1}_{n+1}(w_n)\rangle_\Gamma$. In case $\Gamma=\Gamma^{\circ}$, we conclude setting $\beta_{n+1}=\beta'_{n+1}$. Otherwise, continue to step 6.  
\item (In case $\Gamma\neq \Gamma^{\circ}$) Let $\bar{x}'$ enumerate $X'_{n+1}$ and $\bar{y}'$ be the enumeration of $Y'_{n+1}$ given by $\beta'_{n+1}:\ \bar{x}'\mapsto \bar{y}'$. By \cref{l:generated}(\ref{itm:generated 8}) and recursion hypothesis {\rm{(v)}}, we have $C\coloneqq\cone_\gamma(X'_{n+1})=\cone_\gamma(X_n)=\cone_\gamma(Y_n)=\cone_\gamma(Y'_{n+1})$. If $v_n\in C$, by homogeneity, extend $\beta'_{n+1}$ to a partial isomorphism $\beta_{n+1}$ by adding $v_n$ to the domain and the image. If $v_n\notin C$, applying \cref{l:saturation of cones}, we can find $u$ with $v_n \bar{x}'\equiv^{\Rr\Gamma}u \bar{y}'$ and $u$ in the same cone as $v_n$. By homogeneity, find $u'$ with $u'v_n\bar{x}'\equiv^{\Rr\Gamma}v_nu\bar{y}'$. Extend $\beta'_{n+1}$ to $\beta_{n+1}:\ X_{n+1}\rightarrow Y_{n+1}$ by mapping $v_nu'\mapsto uv_n$, where $X_{n+1}=\langle X'_{n+1}\, u' v_n\rangle_\Gamma$ and $Y_{n+1}=\langle Y'_{n+1}\, v_n u\rangle_{\Gamma}$.
\end{enumerate} 

Now, we check that $\beta_{n+1}$ and $(a_k)_{-n-1\leq k< n+1}$ just constructed satisfy the recursion hypotheses:
\begin{enumerate}[label={(\roman*)}, wide]
\item By construction, $\beta_{n+1}:\ X_{n+1}\rightarrow X_{n+1}$ is a partial isomorphism between substructures extending $\beta_n$ with $w_n,v_n\in X_{n+1}$ and $w_n,v_n\in Y_{n+1}$. 
\item By construction, $a_{-n-1},\alpha^{-1}(a_{-n}),a_n\in X_{n+1}$, $a_{-n}\in X_n\subseteq X_{n+1}$ and $\alpha^{-1}(a_n)=c_n\in X_{n}\subseteq X_{n+1}$. Also, by construction, $\beta_{n+1}\alpha^{-1}(a_n)=\beta_{n+1}(c_n)=\alpha\beta_n(a_{n-1})$. Finally, we get $\beta_{n+1}(a_{-n-1})=\alpha^{-1}(b')$, concluding $\alpha\beta_{n+1}(a_{-n-1})=\beta_{n+1}\alpha^{-1}(a_{-n})$.
\item By construction, $a_n=\alpha(c_n)$ where $c_n=\beta_n^{-1}\alpha\beta_n(a_{n-1})$. Thus, by recursion hypothesis {\rm{(iii)}}, $a_n=\alpha(c_n)>c_n$, so $\alpha(a_n)>\alpha(c_n)=a_n$. Also, by construction, $\alpha(a_{-n-1})>a_{-n-1}$. Finally, $\beta_{n+1}^{-1}\alpha\beta_{n+1}(a_n)=c_{n+1}$ and $\alpha(c_{n+1})>c_{n+1}$. 
\item By recursion hypotheses {\rm{(iii,iv)}}, $a_n=\alpha(c_n)>c_n=\max X_n\cap \Gamma^{\circ}$ and $\alpha^{-1}(a_{-n})<a_{-n}=\min X_n\cap \Gamma^{\circ}$. Since $\beta_{n+1}$ is a partial isomorphism, $b>\max Y_n\cap \Gamma^{\circ}$ and $b'<\min Y_n\cap \Gamma^{\circ}$. By construction, $\alpha(b)>b$ and $\alpha^{-1}(b')<b'$. As $\beta_{n+1}$ is a partial isomorphism, $c_{n+1}>a_n$ and $a_{-n-1}<\alpha^{-1}(a_{-n})$. Also, by construction, $a_{-n-1}<\pi_{\Gamma}(w_n)<c_{n+1}$ and $b'<\pi_{\Gamma}(w_n)<b$. Hence, by \cref{l:generated}(\ref{itm:generated 6}), $a_{-n-1}=\min X_{n+1}\cap \Gamma^{\circ}$ and $c_{n+1}=\max X_{n+1}\cap \Gamma^\circ$.
\item (In case $\Gamma\neq \Gamma^{\circ}$) If $v_n\sim_\gamma v\in X_n$, then $\beta_{n+1}(v_n)\sim_\gamma \beta_{n+1}(v)\sim_\gamma v\sim_\gamma v_n$ by recursion hypothesis {\rm{(v)}}. On the other hand, if $v_n\notin \cone(X_n)$, by construction, $\beta_{n+1}(v_n)$ is in the same cone as $v_n$.  By \cref{l:generated}(\ref{itm:generated 8}), (v) holds.
\end{enumerate}
\end{enumerate}

Set $\beta=\bigcup \beta_n$, so $\beta\in\Aut(\Tt^{M}_\Gamma)$ by property {\rm{(i)}}. 
\begin{enumerate}[label={\rm{(\alph*)}}, wide]
\item For any $x\in \Gamma^{\circ}$, $x=w_n$ for some $n\in\N$. Then, $a_{-n-1}=\min X_{n+1}\leq x\leq \max X_{n+1}=\beta^{-1}\alpha\beta(a_n)<\alpha\beta^{-1}\alpha\beta(a_n)=a_{n+1}$ by properties {\rm{(i,ii,iii,iv)}}. Take $m\coloneqq\min\{n\in\Z\tq x<a_n\}$. Then, $a_{m-1}\leq x< a_m$, so $x<a_m=\alpha\beta^{-1}\alpha\beta(a_{m-1})\leq \alpha\beta^{-1}\alpha\beta(x)$ by property {\rm{(ii)}}. As $x$ is arbitrary, we conclude that $\alpha\beta^{-1}\alpha\beta$ is strictly increasing in $\Gamma^{\circ}$. 
\item (In case $\Gamma\neq \Gamma^{\circ}$) For any $v>\gamma\coloneqq\max \Gamma$, $v=v_n$ for some $n\in\N$. Then, $\beta(v)$ is in the same cone as $v$ by property {\rm{(v)}}. As $v$ is arbitrary, we get that $\beta$ leaves invariant every cone above $\gamma$. \qedhere
\end{enumerate}
\end{proof}

