\label{l:construction 2} Let $\Gamma$ be a semibranch and $\alpha$ an automorphism of $\Tt^M$ fixing $\Gamma$ setwise. Suppose that $\alpha$ is upwards unboundedly increasing and downwards unboundedly decreasing in $\Gamma^{\circ}$. Then, there are an automorphism $\beta$ of $\Tt^M$ fixing $\Gamma$ setwise and $a,a'\in\Gamma^{\circ}$ such that:
\begin{enumerate}[label={\rm{(\alph*)}}]
\item $((\alpha\beta^{-1}\alpha\beta)^n(a))_{n\in\N}$ is strictly increasing and upwards unbounded in $\Gamma^{\circ}$.
\item $((\alpha\beta^{-1}\alpha\beta)^n(a'))_{n\in\N}$ is strictly decreasing and downwards unbounded. 
\item If $\Gamma$ is not a branch, $\beta$ fixes setwise every cone above $\max\Gamma$. 
\end{enumerate}
\begin{proof} Let $W\coloneqq\{w\tq \pi_\Gamma(w)\in \Gamma^{\circ}\}$ and $V\coloneqq\{v\tq \pi_\Gamma(v)\notin \Gamma^{\circ}\}$. Let $(w_n)_{n\in\N}$ be an enumeration of $W$ and $(v_n)_{n\in\N}$ an enumeration of $V$.

By back{\hyp}and{\hyp}forth, we recursively construct a chain of partial finite isomorphisms $(\beta_n)_{n\in\N}$ of $\Tt^M$ setwise fixing $\Gamma$, an increasing sequence $(a_n)_{n\in\N}$ in $\Gamma^\circ$ and a decreasing sequence $(a'_n)_{n\in\N}$ in $\Gamma^\circ$ with the following properties:
\begin{enumerate}[label={(\roman*)}, wide]
\item $\beta_n:\ X_n\rightarrow Y_n$ with $X_n=\langle X_n\rangle_{\Gamma}$ and $Y_n=\langle Y_n\rangle_{\Gamma}$, and $w_k,v_k\in X_n$ and $w_k,v_k\in Y_n$ for $k<n$.
\item For each $0<k<n$, we have $\alpha\beta_n(a_{k-1})=\beta_n\alpha^{-1}(a_k)$ and $\alpha\beta_n(a'_{k-1})=\beta_n\alpha^{-1}(a'_k)$. In particular, $a_k,a'_k\in X_n $ for $k<n-1$, and $\alpha^{-1}(a_k),\alpha^{-1}(a'_k) \in X_n$ for $0<k<n$. 
\item We have $\alpha(a_{k})>a_{k}$ and $\alpha(a'_k)<a'_k$ for $k<n$, and $\alpha(c_n)>c_n$ and $\alpha(c'_n)<c'_n$ where $c_n\coloneqq \beta_n^{-1}\alpha\beta_n(a_{n-1})$ and $c'_n\coloneqq \beta_n^{-1}\alpha\beta_n(a'_{n-1})$. In particular, $a_{n-1},a'_{n-1}\in X_n$ and $\alpha\beta_n(a_{n-1}),\alpha\beta_n(a'_{n-1})\in Y_n$.
\item For $n\geq 1$, $c'_n=\min X_n\cap \Gamma^{\circ}$ and $c_n=\max X_n\cap \Gamma^\circ$.
\item (In case $\Gamma\neq\Gamma^{\circ}$) $\beta_n(v)$ and $v$ are in the same cone above $\gamma\coloneqq \max\Gamma$ for any $v\in X_n$ with $v>\gamma$. Also, $\gamma\in X_n$, $\gamma\in Y_n$ and $\beta_n(\gamma)=\gamma$.
\end{enumerate}

In stage $n$ we construct $\beta_n$, $(a_k)_{k<n}$ and $(a'_k)_{k<n}$.
\begin{enumerate}[wide]
\item[Case $n=0$:] If $\Gamma$ is not a branch, we take $\beta_{0}:\ \gamma\mapsto \gamma$, with $X_{0}=Y_{0}=\{\gamma\}$, where $\gamma\coloneqq\max\Gamma$. If $\Gamma$ is a branch, we take $\beta_0=\emptyset$.
\item[Case $n=1$:] Take any $a_0,a'_0\in\Gamma^{\circ}$ with $a_0>a_0'$ such that $\alpha(a_0)>a_0$ and $\alpha(a'_0)<a'_0$. Applying sequentially \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 1}) twice and then \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 2}) twice (with $\alpha^{-1}$), we find $b,c_1,b',c_1'\in\Gamma^{\circ}$ with $b'<\pi_\Gamma(w_0)<b$ and $c'_1<\pi_\Gamma(w_0)<c_1$ such that $\alpha(b)>b$, $\alpha(c_1)>c_1$, $b'>\alpha(b')$, $c'_1>\alpha(c'_1)$ and $a_0c_1a'_0c'_1\equiv^{\Rr\Gamma}b\alpha(b)b'\alpha(b')$. By homogeneity, we extend $\beta_0$ to $\beta'_1:\ X'_1\rightarrow Y'_1$ with $\beta_1':\ a_0c_1a'_0c'_1\mapsto b\alpha(b)b'\alpha(b')$ and $w_0\in X_1'\cap Y'_1$. Further, we restrict $\beta'_1$ so that $X'_1=\langle X_0\, a_0c_1a'_0c'_1w_0{\beta'}^{-1}_1(w_0)\rangle_\Gamma$. If $\Gamma=\Gamma^{\circ}$, we set $\beta_1=\beta_1'$. If $\Gamma\neq\Gamma^\circ$, by \cref{l:saturation of cones} and homogeneity, we extend $\beta'_1$ to $\beta_1:\ X_1\rightarrow Y_1$ by adding $v_0$ to the domain and the image such that $v_0$ and $\beta_1(v_0)$ are in the same cone. As above, we restrict so that $X_1=\langle X_0\, v_0 \beta_1^{-1}(v_0)\rangle_\Gamma$.

Obviously, $\beta_1$ satisfies {\rm{(i)}}. For {\rm{(ii)}} there is nothing to check. By construction, $c_1=\beta_1^{-1}\alpha\beta(a_0)$ and $c'_1=\beta_1^{-1}\alpha\beta_1(a'_0)$, and we have $\alpha(a_0)>a_0$, $\alpha(a'_0)<a'_0$, $\alpha(c_1)>c_1$ and $\alpha(c'_1)<c'_1$, so we get {\rm{(iii)}}. By construction, $\alpha(b')<b'<\pi_\Gamma(w_0)<b<\alpha(b)$, so applying $\beta^{-1}_1$ we get $c'_1<a'_0<\pi_\Gamma(\beta^{-1}(w_0))<a_0<c_1$. On the other hand, $c'_1<\pi_\Gamma(w_0)<c_1$ too. Hence, by \cref{l:generated}(\ref{itm:generated 6}), we get that $c_1=\max X_1\cap \Gamma^{\circ}$ and $c'_1=\min X_1\cap \Gamma^{\circ}$, so {\rm{(iv)}} holds. Finally, in case $\Gamma\neq\Gamma^{\circ}$, by \cref{l:generated}(\ref{itm:generated 8}), we have $\cone(X_1)=\cone_\gamma(v_0)$, so {\rm{(v)}} holds.
\item[Recursion case (case $n+1$):] Suppose $\beta_n:\ X_n\rightarrow Y_n$, $(a_k)_{k<n}$ and $(a'_k)_{k<n}$ are already given for $n\geq 1$. Let $\bar{x}$ enumerate $X_n$ and $\bar{y}$ be the enumeration of $Y_n$ given by $\beta_n:\ \bar{x}\mapsto \bar{y}$.
\begin{enumerate}[label={\rm{Step {\arabic*}:}}, wide]
\item By recursion hypothesis {\rm{(iv)}}, we know that $c_n=\max X_n\cap \Gamma^\circ$ where $c_n\coloneqq\beta_n^{-1}\alpha\beta_n(a_{n-1})$. Set $a_n\coloneqq\alpha(c_n)$. By recursion hypothesis {\rm{(iii)}}, $a_n=\alpha(c_n)>c_n$. Hence, by \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 1}), we can find $b\in\Gamma^\circ$ with $\alpha(b)>b$ and $b>\pi_{\Gamma}(w_n)$ such that $a_n\bar{x}\equiv^{\Rr\Gamma} b\bar{y}$.
\item Applying \cref{l:saturation of increasing points}(\ref{itm:saturation of increasing points 1}) again, we can find $c_{n+1}\in\Gamma^{\circ}$ with $\alpha(c_{n+1})>c_{n+1}$ and $c_{n+1}>\pi_{\Gamma}(w_{n})$ such that $c_{n+1}a_n\bar{x}\equiv^{\Rr\Gamma}\alpha(b)b\bar{y}$.
