\item By homogeneity, we extend $\beta_n$ to a partial isomorphism $\beta'_{n+1}:\ X'_{n+1}\rightarrow Y'_{n+1}$ with $\beta'_{n+1}:\ c'_{n+1}a'_nc_{n+1}a_n\mapsto \alpha(b')b'\alpha(b)b$ and $w_n\in X'_{n+1}\cap Y'_{n+1}$. Further, we restrict $\beta'_{n+1}$ so that $X'_{n+1}=\langle X_n\, c'_{n+1}a'_nc_{n+1}a_nw_n{\beta'}^{-1}_{n+1}(w_n)\rangle_\Gamma$. In case $\Gamma=\Gamma^{\circ}$, we conclude setting $\beta_{n+1}=\beta'_{n+1}$. Otherwise, continue to step 6.  
\item (In case $\Gamma\neq \Gamma^{\circ}$) By recursion hypothesis {\rm{(v)}}, \cref{l:saturation of cones} and homogeneity, we can extend $\beta''_{n+1}$ to a partial elementary map $\beta_{n+1}$ by adding $v_n$ to the domain and the image such that $v_n$ and $\beta_{n+1}(v_n)$ are in the same cone. As above, we restrict so that $X_{n+1}=\langle X'_n\, v_n \beta_{n+1}^{-1}(v_n)\rangle_\Gamma$.
\end{enumerate}

Now, we check that $\beta_{n+1}$, $(a_k)_{k<n+1}$ and $(a'_k)_{k<n+1}$ just constructed satisfy the recursion hypotheses:
\begin{enumerate}[label={(\roman*)}, wide]
\item By construction, $\beta_{n+1}:\ X_{n+1}\rightarrow Y_{n+1}$ is a partial isomorphism extending $\beta_n$ with $w_n,v_n\in X_{n+1}$ and $w_n,v_n\in Y_{n+1}$. 
\item By construction, $c'_{n+1},a'_n,c_{n+1},a_n\in X_{n+1}$. Also, we have $\alpha^{-1}(a_n)=c_n\in X_{n}\subseteq X_{n+1}$ and $\alpha^{-1}(a'_n)=c'_n\in X_n\subseteq X_{n+1}$, so $\beta_{n+1}\alpha^{-1}(a_n)=\beta_{n+1}(c_n)=\alpha\beta_n(a_{n-1})$ and $\beta_{n+1}\alpha^{-1}(a'_n)=\beta_{n+1}(c'_n)=\alpha\beta_n(a'_{n-1})$ by recursion hypothesis {\rm{(iii)}}.
\item  By construction, $a_n=\alpha(c_n)$ and $a'_n=\alpha(c'_n)$ where $c_n=\beta_n^{-1}\alpha\beta_n(a_{n-1})$ and $c'_n=\beta_n^{-1}\alpha\beta_n(a'_{n-1})$. Thus, by recursion hypothesis {\rm{(iii)}}, $a_n=\alpha(c_n)>c_n$ and $a'_n=\alpha(c'_n)<c'_n$, so $\alpha(a_n)>\alpha(c_n)=a_n$ and $\alpha(a'_n)<\alpha(c'_n)=a'_n$. On the other hand, $\beta_{n+1}^{-1}\alpha\beta_{n+1}(a_n)=c_{n+1}$ and $\beta_{n+1}^{-1}\alpha\beta_{n+1}(a'_n)=c'_{n+1}$ where $\alpha(c_{n+1})>c_{n+1}$ and $\alpha(c'_{n+1})<c'_{n+1}$. 
\item By recursion hypotheses {\rm{(iii,iv)}}, $a_n=\alpha(c_n)>c_n=\max X_n\cap \Gamma^{\circ}$ and $a'_n=\alpha(c'_n)<c'_n=\min X_n\cap \Gamma^{\circ}$. By construction, $\alpha(b)>b$ and $\alpha(b')<b'$. Applying $\beta^{-1}_{n+1}$, we get $c_{n+1}>a_n$ and $c'_{n+1}<a'_n$. Also, by construction, $c'_{n+1}<\pi_{\Gamma}(w_n)<c_{n+1}$ and $b'<\pi_{\Gamma}(w_n)<b$. Hence, by \cref{l:generated}(\ref{itm:generated 6}), $c'_{n+1}=\min X_{n+1}\cap \Gamma^{\circ}$ and $c_{n+1}=\max X_{n+1}\cap \Gamma^\circ$.
\item (In case $\Gamma\neq \Gamma^{\circ}$) By construction applying \cref{l:generated}(\ref{itm:generated 8}).
\end{enumerate}
\end{enumerate}

Set $\beta=\bigcup \beta_n$, so $\beta\in\Aut(\Tt^{M}_\Gamma)$ by property {\rm{(i)}}. Set $a=a_0$ and $a'=a'_0$. For any $x\in \Gamma^{\circ}$, $x=w_n$ for some $n\in\N$. Then, $a'_{n+1}=\alpha(c'_{n+1})<c'_{n+1}=\min X_{n+1}\cap \Gamma^{\circ}\leq x\leq \max X_{n+1}\cap\Gamma^{\circ}=c_{n+1}< \alpha(c_{n+1})=a_{n+1}$ by properties {\rm{(i,ii,iii,iv)}}. The same is true for $x=a_n$ or $x=a'_n$. 
\begin{enumerate}[label={\rm{(\alph*)}}, wide]
\item By property {\rm{(ii)}}, $a_k=(\alpha\beta^{-1}\alpha\beta)^k(a)$. The sequence $(a_k)_{k\in\N}$ is strictly increasing and, for any $x\in \Gamma^\circ$, $x\in X_n$ for some $n$, so $x<\max X_n\cap \Gamma^\circ=c_n<\alpha(c_n)=a_n$ by properties {\rm{(iii,iv)}}, concluding that $(a_k)_{k\in\N}$ is upwards unbounded. 
\item By property {\rm{(ii)}}, $a'_k=(\alpha\beta^{-1}\alpha\beta)^k(a')$. The sequence $(a'_k)_{k\in\N}$ is strictly decreasing and, for any $x\in \Gamma^\circ$, $x\in X_n$ for some $n$, so $x>\min X_n\cap \Gamma^\circ=c'_n>\alpha(c'_n)=a'_n$ by properties {\rm{(iii,iv)}}, concluding that $(a'_k)_{k\in\N}$ is downwards unbounded.
\item (In case $\Gamma\neq\Gamma^{\circ}$) For any $v>\gamma\coloneqq\max\Gamma$, $v=v_n$ for some $n\in\N$. Then, $\beta(v)$ is in the same cone as $v$ by property {\rm{(v)}}. As $v$ is arbitrary, we get that $\beta$ setwise fixes every cone above $\gamma$. \qedhere
\end{enumerate}
\end{proof}

