semantic_equivalence_artifact.original_latex_theorem:
\label{l:construction 3} Let $\Gamma$ be a semibranch and $\alpha$ an automorphism of $\Tt^M$ fixing $\Gamma$ setwise. Suppose that there are $a,a'\in \Gamma^\circ$ with $(\alpha^n(a))_{n\in\N}$ strictly increasing and upwards unbounded in $\Gamma^{\circ}$ and $(\alpha^n(a'))_{n\in\N}$ strictly decreasing and downwards unbounded in $\Gamma^\circ$. Then, there is an automorphism $\beta$ of $\Tt^M$ fixing $\Gamma$ setwise such that:
\begin{enumerate}[label={\rm{(\alph*)}}, wide]
\item $\alpha^{-1}\beta^{-1}\alpha\beta$ is strictly increasing in $\Gamma^{\circ}$. 
\item If $\Gamma$ is not a branch, $\beta$ setwise fixes every cone above $\max\Gamma$. 
\end{enumerate}
\begin{proof} First of all, note that it follows from the assumptions that $\alpha$ is strictly decreasing in $\Gamma^{\circ}_{<a'}$ and strictly increasing in $\Gamma^{\circ}_{>a}$. In particular, $a>a'$.

Let $W\coloneqq\{w\tq \pi_\Gamma(w)\in \Gamma^{\circ}\}$ and $V\coloneqq\{v\tq \pi_\Gamma(v)\notin \Gamma^{\circ}\}$. Let $(w_n)_{n\in\N}$ be an enumeration of $W$ and $(v_n)_{n\in\N}$ an enumeration of $V$. Without loss of generality, assume $\pi_\Gamma(w_0)>a$.  Let 
\[l(n)\coloneqq\min\{k\in\N\tq \pi_\Gamma(w_k)\leq \alpha^{\lfloor (n-1)/2\rfloor}(a')\mathrm{\ or\ }\pi_\Gamma(w_k)\geq \alpha^{\lfloor (n-1)/2\rfloor}(a)\}.\]
Note that, since $(\alpha^n(a))_{n\in\N}$ is upwards unbounded and $(\alpha^n(a'))_{n\in\N}$ is downwards unbounded, we get that $l(n)\rightarrow\infty$.

By back{\hyp}and{\hyp}forth, we recursively construct a chain of partial finite isomorphisms $(\beta_n)_{n\in\N}$ of $\Tt^M$ setwise fixing $\Gamma$, and an increasing sequence $(a_n)_{n\in\Z}$ of elements in $\Gamma^\circ$ with the following properties:
\begin{enumerate}[label={(\roman*)}, wide]
\item $\beta_n:\ X_n\rightarrow Y_n$ with $X_n=\langle X_n\rangle_{\Gamma}$ and $Y_n=\langle Y_n\rangle_{\Gamma}$, and $w_k,v_k\in X_n$ and $w_k,v_k\in Y_n$ for every $k<l(n)$.
\item For each $-n<k<n$, we have $\alpha\beta_n(a_{k-1})=\beta_n\alpha(a_k)$. In particular, $a_k\in X_n$ for $-n-1<k<n-1$, and $\alpha(a_k)\in X_n$ for $-n<k<n$.  
\item For $n\geq 1$, we have $a_1>a>a'>a_0$ and $\beta_n(a_0)>a>a'>\beta_n(a_{-1})$. Furthermore, we have $a_k>\alpha^{k-1}(a)$ for $0<k<n$; $\beta_n(a_k)>\alpha^{\lfloor k/2\rfloor}(a)$ for $0\leq k<n$; $a_k<\alpha^{\lfloor -k/2\rfloor}(a')$ for $-n\leq k\leq 0$, and $\beta_n(a_k)<\alpha^{-k-1}(a')$ for $-n\leq k<0$.
\item For $n\geq 1$, we have $\alpha(a_{-n+1})=\min X_n\cap \Gamma^{\circ}$ and $c_{n}=\max X_n\cap \Gamma^\circ$ with $c_n>\alpha^2(a_{n-1})$ and $c_n>\alpha(a)$ where $c_n\coloneqq\beta_n^{-1}\alpha\beta_n(a_{n-1})$. In particular, $a_{n-1}\in X_n$ and $\alpha\beta_n(a_{n-1})\in Y_n$. 
\item (In case $\Gamma\neq \Gamma^{\circ}$) $\beta_n(v)$ and $v$ are in the same cone above $\gamma\coloneqq \max\Gamma$ for any $v\in X_n$ with $v>\gamma$. Also, $\gamma\in X_n$, $\gamma\in Y_n$ and $\beta_n(\gamma)=\gamma$.
\end{enumerate}

In stage $n$ we construct $\beta_n$ and $(a_k)_{-n\leq k<n}$.
\begin{enumerate}[wide]
\item[Case $n=0$:] If $\Gamma$ is not a branch, we take $\beta_{0}:\ \gamma\mapsto \gamma$, with $X_{0}=Y_{0}=\{\gamma\}$, where $\gamma\coloneqq\max\Gamma$. If $\Gamma$ is a branch, we take $\beta_0=\emptyset$.
\item[Case $n=1$:] Take $a_0<a'$ arbitrary. Applying \cref{l:saturation of branch intervals} twice, we find $b,b'\in \Gamma^{\circ}$ with $b'<\alpha(a')<a'<a<b$ such that $a_0\alpha(a_0)\equiv^{\Rr\Gamma}bb'$. Applying \cref{l:saturation of branch intervals} again, we find $c_1>\alpha(a)$ such that $a_0\alpha(a_0)c_1\equiv^{\Rr\Gamma}bb'\alpha(b)$. By homogeneity, we find $a_{-1}$ with $a_0\alpha(a_0)c_1a_{-1}\equiv^{\Rr\Gamma}bb'\alpha(b)\alpha^{-1}(b')$. By homogeneity, we extend $\beta_0$ to $\beta'_1:\ X'_1\rightarrow Y'_1$ with $\beta'_1:\ a_0\alpha(a_0)c_1a_{-1}\mapsto bb'\alpha(b)\alpha^{-1}(b')$. Further, we restrict $\beta'_1$ so that $X_1'=\langle X_0\, a_0\alpha(a_0)c_1a_{-1}\rangle_\Gamma$. If $\Gamma=\Gamma^{\circ}$, we set $\beta_1=\beta_1'$. If $\Gamma\neq\Gamma^\circ$, let $\bar{x}'$ enumerate $X'_1$ and $\bar{y}'$ be the enumeration of $Y'_1$ given by $\beta_1':\ \bar{x}'\mapsto \bar{y}'$. By \cref{l:saturation of cones} and homogeneity, we extend $\beta'_1$ to $\beta_1:\ X_1\rightarrow Y_1$ by adding $v_0$ to the domain and the image such that $v_0$ and $\beta_1(v_0)$ are in the same cone. As above, we restrict so that $X_1=\langle X_0\, v_0\beta^{-1}_1(v_0)\rangle_\Gamma$.

Since $\pi_\Gamma(w_0)>a$, we get $l(1)=0$, so $\beta_1$ satisfies {\rm{(i)}} vacuously. If $-1<k<1$, then $k=0$ and $\alpha\beta_1(a_{-1})=b'=\beta_1\alpha(a_0)$, so {\rm{(ii)}} holds. Since $b'<\alpha(a')$, we get $\beta_1(a_{-1})=\alpha^{-1}(b')<a'$, while obviously $a_0<a'<a<b=\beta_1(a_0)$. In particular, $\beta_1(a_{-1})<a'<\beta_1(a_0)$, so $a_{-1}<a_0$ too. Thus, we get {\rm{(iii)}}. By construction, $c_1=\beta_1^{-1}\alpha\beta(a_0)$, and $c_1>\alpha(a)>a>a_0>\alpha^2(a_0)$. Also, $b'<\alpha^{-1}(b')<a'<a<b<\alpha(b)$, getting $\alpha(a_0)<a_{-1}<a_0<c_1$ by applying $\beta^{-1}_1$. Hence, by \cref{l:generated}(\ref{itm:generated 6}), we get that $c_1=\max X_1\cap \Gamma^{\circ}$ and $\alpha(a_0)=\min X_1\cap \Gamma^{\circ}$, so {\rm{(iv)}} holds. Finally, by \cref{l:generated}(\ref{itm:generated 8}), we have $\cone(X_1)=\cone_\gamma(v_0)$, so {\rm{(v)}} holds.
\item[Recursion case (case $n+1$):] Suppose $\beta_n:\ X_n\rightarrow Y_n$ and $(a_k)_{-n\leq k<n}$ are already given where $n\geq 1$. Let $\bar{x}$ enumerate $X_n$ and $\bar{y}$ be the enumeration of $Y_n$ given by $\beta_n:\ \bar{x}\mapsto \bar{y}$. 
\begin{enumerate}[label={\rm{Step {\arabic*}:}}, wide]
\item Set $a_n\coloneqq\alpha^{-1}(c_n)$ where $c_n\coloneqq\beta_n^{-1}\alpha\beta_n(a_{n-1})$. By recursion hypothesis, $a_n\in \Gamma^{\circ}$. By homogeneity, find $b\in\Gamma^\circ$ such that $a_n\bar{x}\equiv^{\Rr\Gamma} b\bar{y}$. 
\item When $n>1$, by recursion hypotheses {\rm{(iii, iv)}}, $a_n=\alpha^{-1}(c_n)>\alpha(a_{n-1})>a_{n-1}>a_0$. When $n=1$, $a_1=\alpha^{-1}(c_1)>a>a_0$ by recursion hypothesis {\rm{(iii,iv)}}. 

Hence, $b>\beta_n(a_{n-1})\geq \beta_n(a_0)>a$ by recursion hypothesis {\rm{(iii)}}, concluding that $\alpha(b)>b$. By recursion hypothesis {\rm{(iv)}}, we also get $\alpha(b)>\alpha\beta_n(a_{n-1})=\beta_n(c_n)=\max Y_n\cap \Gamma^{\circ}$. Thus, by \cref{l:saturation of branch intervals}, find $c_{n+1}\in\Gamma^{\circ}$ such that $c_{n+1}a_n\bar{x}\equiv^{\Rr\Gamma} \alpha(b)b\bar{y}$ with $c_{n+1}>\alpha^2(a_n)$. Note that, since $\alpha(b)>\max Y_n\cap \Gamma^{\circ}$ and $\alpha(b)>b$, we get $c_{n+1}>\max X_n\cap \Gamma^{\circ}$ and $c_{n+1}>a_n$.
