Now, we check that $\beta_{n+1}$ and $(a_k)_{-n-1\leq k<n+1}$ just constructed satisfy the recursion hypotheses:
\begin{enumerate}[label={(\roman*)}, wide]
\item By construction, $\beta_{n+1}:\ X_{n+1}\rightarrow Y_{n+1}$ is a partial isomorphism extending $\beta_n$ with $w_k,v_k\in X_{n+1}$ and $w_k,v_k\in Y_{n+1}$ for $k<l(n+1)$.
\item By construction, $a_{-n-1},\alpha(a_{-n}),a_n\in X_{n+1}$, $a_{-n}\in X_n\subseteq X_{n+1}$ and $\alpha(a_n)=c_n\in X_{n}\subseteq X_{n+1}$. Also, by construction, $\beta_{n+1}\alpha(a_n)=\beta_{n+1}(c_n)=\alpha\beta_n(a_{n-1})$. Finally, we get that $\beta_{n+1}(a_{-n-1})=\alpha^{-1}(b')$, so $\alpha\beta_{n+1}(a_{-n-1})=\beta_{n+1}\alpha(a_{-n})$.
\item By recursion hypothesis {\rm{(iii)}}, we have that $a'>a_0$ and $\beta_n(a_0)>a>a'>\beta_n(a_{-1})$. 

When $n=1$, by recursion hypothesis {\rm{(iv)}}, we have that $a_1=\alpha^{-1}(c_1)>a>a_0$. For $n>1$, by construction and recursion hypotheses {\rm{(iii,iv)}}, $a_n=\alpha^{-1}(c_n)>\alpha(a_{n-1})>a_{n-1}$. On the other hand, by construction, $\beta_{n+1}(a_{-n-1})=\alpha^{-1}(b')<\beta_n\alpha(a_{-n+1})$, concluding that $a_{-n-1}<\alpha(a_{-n+1})$. In particular, as $\alpha(a_{-n+1})=\min X_n\cap\Gamma^{\circ}\leq a_{-n}$ by recursion hypothesis {\rm(iv)}, we get $a_{-n-1}<a_{-n}$. Thus, $(a_k)_{-n-1\leq k<n+1}$ is strictly increasing with $a_1>a>a'>a_0$.

As we have already noted, $a_1>a$ and $a_n>\alpha(a_{n-1})$ for $n>1$, concluding $a_n>\alpha^{n-1}(a)$ by recursion hypothesis {\rm{(iii)}}. Similarly, $a_{-1}<a_0<a'$ and $a_{-n-1}<\alpha(a_{-n+1})$, concluding $a_{-n-1}<\alpha^{\lfloor (n+1)/2\rfloor}(a')$ by recursion hypothesis {\rm{(iii)}}.

For $n=1$, $\beta_2(a_1)>\beta_2(a_0)>a$. For $n>1$, by recursion hypothesis {\rm{(iv)}}, $a_n=\alpha^{-1}(c_n)>\alpha(a_{n-1})$, so $\beta_{n+1}(a_n)>\beta_{n+1}\alpha(a_{n-1})$. Thus, by recursion hypotheses {\rm{(ii,iii)}}, $\beta_{n+1}(a_n)>\beta_n\alpha(a_{n-1})=\alpha\beta_n(a_{n-2})>\alpha\circ\alpha^{\lfloor (n-2)/2\rfloor}(a)=\alpha^{\lfloor n/2\rfloor}(a)$. 

Finally, by construction, $b'<\alpha\beta_n\alpha(a_{-n+1})$ where $\beta_{n+1}(a_{-n-1})=\alpha^{-1}(b')$. Thus, $\beta_{n+1}(a_{-n-1})<\beta_n\alpha(a_{-n+1})$, getting $\beta_{n+1}(a_{-n-1})<\alpha\beta_n(a_{-n})$ by recursion hypothesis {\rm{(ii)}}. Hence, $\beta_{n+1}(a_{-n-1})<\alpha\circ\alpha^{n-1}(a')=\alpha^{n}(a')$ by recursion hypothesis {\rm{(iii)}}.
\item By construction, $c_{n+1}>\max X_n\cap \Gamma^{\circ}$ and $c_{n+1}>a_n$, and $\alpha(a_{-n})<\min X_n\cap\Gamma^{\circ}$. Also, $b'<a'$, so $b'<\alpha^{-1}(b')$, getting $\alpha(a_{-n})<a_{-n-1}$ by applying $\beta_{n+1}$. Now, by property {\rm{(iii)}}, $c_{n+1}>a_n>\alpha^{\lfloor n/2\rfloor}(a)>\pi_{\Gamma}(w_k)>\alpha^{\lfloor n/2 \rfloor}(a')>a_{-n-1}>\alpha(a_{-n})$ and $\beta_{n+1}(c_{n+1})>\beta_{n+1}(a_n)>\alpha^{\lfloor n/2\rfloor}(a)>\pi_{\Gamma}(w_k)>\alpha^{\lfloor n/2 \rfloor}(a')>\beta_{n+1}(a_{-n-1})>\alpha(a_{-n})$  for any $k<l(n+1)$. Hence, $c_{n+1}=\max X_{n+1}\cap \Gamma^{\circ}$ and $\alpha(a_{-n})=\min X_{n+1}\cap \Gamma^{\circ}$.
\item (In case $\Gamma\neq \Gamma^{\circ}$) By construction.
\end{enumerate}
\end{enumerate}

Set $\beta=\bigcup \beta_n$, so $\beta\in\Aut(\Tt^{M}_\Gamma)$ by {\rm{(i)}} noting that $l(n)\rightarrow \infty$. 
\begin{enumerate}[label={\rm{(\alph*)}}, wide]
\item For any $x\in \Gamma^{\circ}$, $x=w_k$ for some $k\in\N$ and $k<l(n)$ for some $n$. Thus, $a_{-n}<x< a_n$ by property {\rm{(iii)}}. Take $m\coloneqq\min\{n\in\Z\tq x<a_n\}$. Then, $a_{m-1}\leq x< a_m$, so $x<a_m=\alpha^{-1}\beta^{-1}\alpha\beta(a_{k-1})\leq \alpha^{-1}\beta^{-1}\alpha\beta(x)$. As $x$ is arbitrary, we conclude that $\alpha^{-1}\beta^{-1}\alpha\beta$ is strictly increasing in $\Gamma^{\circ}$. 
\item (In case $\Gamma\neq \Gamma^{\circ}$) For any $v>\gamma\coloneqq\max \Gamma$, $v=v_n$ for some $n\in\N$. Then, $\beta(v)$ is in the same cone as $v$. As $v$ is arbitrary, we get that $\beta$ leaves invariant every cone above $\gamma$.\qedhere
\end{enumerate}
\end{proof}

